if (! function_exists('image_downloader')) {
    function image_downloader($url, $filename = null, $output_dir = null, $max_size_bytes = null, $timeout = null, $verify = null)
    {
        // Image Downloader v2 — always use correct extension from magic bytes
        $url = $url ?? '';
        $filename = $filename ?? '';
        $output_dir = $output_dir ?? 'downloads';
        $max_size_bytes = $max_size_bytes ?? 10485760;
        $timeout = $timeout ?? 30;
        $verify = $verify ?? true;

        if (empty($url)) return ['error' => 'URL is required', 'success' => false];
        if (!preg_match('#^https?://#i', $url)) return ['error' => 'URL must start with http:// or https://', 'success' => false];
        $max_size_bytes = max(102400, min(52428800, (int)$max_size_bytes));
        $timeout = max(5, min(60, (int)$timeout));

        $workspace = __DIR__ . '/../workspace';
        $out_dir = $workspace . '/' . ltrim($output_dir, '/');
        if (!is_dir($out_dir)) @mkdir($out_dir, 0777, true);

        // HEAD request
        $ctx_head = stream_context_create([
            'http' => ['method' => 'HEAD', 'timeout' => 10, 'header' => "User-Agent: image_downloader/1.0\r\n", 'ignore_errors' => true],
            'ssl' => ['verify_peer' => false, 'verify_peer_name' => false],
        ]);
        $content_type = '';
        $content_length = 0;
        $status_code = 200;
        @file_get_contents($url, false, $ctx_head);
        if (isset($http_response_header)) {
            foreach ($http_response_header as $h) {
                if (stripos($h, 'Content-Type:') === 0) $content_type = trim(substr($h, 13));
                elseif (stripos($h, 'Content-Length:') === 0) $content_length = (int)trim(substr($h, 15));
                elseif (preg_match('#^HTTP/\d+\.\d+ (\d+)#', $h, $m)) $status_code = (int)$m[1];
            }
        }
        if ($status_code >= 400) return ['error' => "HTTP $status_code", 'success' => false];
        if ($content_length > $max_size_bytes) return ['error' => "Too large: $content_length bytes", 'success' => false];

        // GET
        $ctx_get = stream_context_create([
            'http' => ['method' => 'GET', 'timeout' => $timeout, 'header' => "User-Agent: image_downloader/1.0\r\n", 'ignore_errors' => true],
            'ssl' => ['verify_peer' => false, 'verify_peer_name' => false],
        ]);
        $start = microtime(true);
        $data = @file_get_contents($url, false, $ctx_get);
        $elapsed_ms = round((microtime(true) - $start) * 1000);
        if ($data === false) return ['error' => 'Download failed', 'success' => false];
        $size = strlen($data);
        if ($size > $max_size_bytes) return ['error' => "Too large: $size bytes", 'success' => false];
        if ($size === 0) return ['error' => 'Empty file', 'success' => false];

        // Magic byte detection (ordered by specificity)
        $magic_db = [
            "\xFF\xD8\xFF" => ['ext' => 'jpg', 'mime' => 'image/jpeg', 'name' => 'JPEG'],
            "\x89\x50\x4E\x47\x0D\x0A\x1A\x0A" => ['ext' => 'png', 'mime' => 'image/png', 'name' => 'PNG'],
            "\x47\x49\x46\x38\x37\x61" => ['ext' => 'gif', 'mime' => 'image/gif', 'name' => 'GIF'],
            "\x47\x49\x46\x38\x39\x61" => ['ext' => 'gif', 'mime' => 'image/gif', 'name' => 'GIF'],
            "\x52\x49\x46\x46" => ['ext' => 'webp', 'mime' => 'image/webp', 'name' => 'WEBP'],
            "\x42\x4D" => ['ext' => 'bmp', 'mime' => 'image/bmp', 'name' => 'BMP'],
            "\x3C\x73\x76\x67" => ['ext' => 'svg', 'mime' => 'image/svg+xml', 'name' => 'SVG'],
            "\x3C\x3F\x78\x6D\x6C" => ['ext' => 'svg', 'mime' => 'image/svg+xml', 'name' => 'SVG'],
            "\x00\x00\x01\x00" => ['ext' => 'ico', 'mime' => 'image/x-icon', 'name' => 'ICO'],
            "\x50\x4B\x03\x04" => ['ext' => 'zip', 'mime' => 'application/zip', 'name' => 'ZIP'],
            "\x25\x50\x44\x46" => ['ext' => 'pdf', 'mime' => 'application/pdf', 'name' => 'PDF'],
        ];

        $detected = ['ext' => 'bin', 'mime' => 'application/octet-stream', 'name' => 'Binary'];
        foreach ($magic_db as $magic => $info) {
            if (str_starts_with($data, $magic)) {
                $detected = $info;
                // WEBP check: verify RIFF subtype
                if ($detected['ext'] === 'webp' && strlen($data) > 12 && substr($data, 8, 4) !== 'WEBP') {
                    $detected = ['ext' => 'bin', 'mime' => $content_type ?: 'application/octet-stream', 'name' => 'RIFF'];
                }
                break;
            }
        }

        // SVG fallback from Content-Type
        if ($detected['ext'] === 'bin' && stripos($content_type, 'svg') !== false) {
            $detected = ['ext' => 'svg', 'mime' => 'image/svg+xml', 'name' => 'SVG'];
        }

        // Determine filename stem (no extension)
        $url_path = parse_url($url, PHP_URL_PATH);
        $url_basename = $url_path ? basename($url_path) : 'download';
        $url_basename = preg_replace('/\?.*/', '', $url_basename);
        $stem = pathinfo($url_basename, PATHINFO_FILENAME);

        if (!empty($filename)) {
            $stem = preg_replace('/\.[^.]+$/', '', $filename); // strip any extension user provided
            $stem = preg_replace('/[^a-zA-Z0-9_-]/', '_', $stem);
        }

        if (empty($stem)) $stem = 'download';

        // Build filename with CORRECT extension from detection
        $final_name = $stem . '.' . $detected['ext'];
        $filepath = $out_dir . '/' . $final_name;

        // Deduplicate
        $counter = 1;
        while (file_exists($filepath)) {
            $final_name = $stem . '_' . $counter . '.' . $detected['ext'];
            $filepath = $out_dir . '/' . $final_name;
            $counter++;
        }

        $written = file_put_contents($filepath, $data);
        if ($written === false) return ['error' => 'Write failed', 'success' => false];

        clearstatcache(true, $filepath);
        $actual_size = filesize($filepath);
        $rel_path = 'storage/agent/workspace/' . ltrim($output_dir, '/') . '/' . $final_name;

        $result = [
            'success' => true,
            'url' => $url,
            'filename' => $final_name,
            'path' => $rel_path,
            'size_bytes' => $actual_size,
            'download_time_ms' => $elapsed_ms,
            'detected_format' => $detected['name'],
            'detected_extension' => $detected['ext'],
            'mime_type' => $detected['mime'],
            'content_type_header' => $content_type ?: 'N/A',
            'md5' => md5($data),
            'sha256' => hash('sha256', $data),
        ];

        // Verify with image_info for known image formats
        $image_exts = ['jpg', 'jpeg', 'png', 'gif', 'webp', 'bmp'];
        if ($verify && in_array($detected['ext'], $image_exts)) {
            $result['verification_hint'] = "Use: image_info path=\"$rel_path\"";
            $result['can_verify_with_gd'] = true;
        } elseif ($verify && $detected['ext'] === 'svg') {
            $result['verification'] = 'SVG saved (' . $actual_size . ' bytes)';
        }

        return $result;
    }
